sub extract_pdf_info {
    my ($pdf_file) = @_;
    my $pdf = PDF::API2->open($pdf_file);

    my $author = '';
    my $title = '';
    my $table = '';
    my $in_table = 0;

    foreach my $page (1 .. $pdf->pages) {
        my $text = extract_text_from_page($pdf->page($page));

        # Extract author and title
        if ($text =~ /Author:\s*(.*)/i) {
            $author = $1;
        }
        if ($text =~ /Title:\s*(.*)/i) {
            $title = $1;
        }

        # Identify and extract table
        if ($text =~ /\b(?:Table|Table of Contents)\b/i) {
            $in_table = 1;
        }
        if ($in_table) {
